--
-- Name: v_parent_children; Type: VIEW; Schema: public; Owner: ufm_admin
--

CREATE VIEW public.v_parent_children AS
 SELECT p.chunk_id AS parent_chunk_id,
    p.section_path AS parent_section_path,
    p.section_name AS parent_section_name,
    p.content AS parent_content,
    p.program_level,
    p.ma_nganh,
    c.chunk_id AS child_chunk_id,
    c.content AS child_content,
    c.chunk_index AS child_chunk_index,
    c.overlap_tokens AS child_overlap_tokens,
    c.token_count AS child_token_count
   FROM (public.knowledge_chunks p
     JOIN public.knowledge_chunks c ON (((c.parent_id)::text = (p.chunk_id)::text)))
  WHERE (((p.chunk_level)::text = 'parent'::text) AND ((c.chunk_level)::text = 'child'::text) AND (p.is_active = true) AND (c.is_active = true))
  ORDER BY p.chunk_id, c.chunk_index;


ALTER VIEW public.v_parent_children OWNER TO ufm_admin;

