823dcf72-d9fd-478b-8af7-6fd035aa0397	1bb14cee-4fd3-406d-8520-275f897761b4	quytrinhdanhgia-luanvan-thacsi.md	Quy định	Quy định	\N	thac_si	\N	1	9	# QUY TRÌNH CHẤT LƯỢNG\n# ĐÁNH GIÁ LUẬN VĂN/ĐỀ ÁN THẠC SĨ\nMã số quy trình: QT/SĐH/06\n[Nguồn: quytrinhdanhgia-luanvan-thacsi.md]\n[Mục: Quy định]\n\n*1. Người có liên quan phải nghiên cứu và thực hiện đúng các nội dung của quy trình này.*\n*2. Nội dung trong quy trình này có hiệu lực thi hành như sự chỉ đạo của Hiệu trưởng.*\n*3. Mỗi đơn vị được cung cấp 01 bản file điện tử. Các đơn vị khi có nhu cầu bổ sung thêm tài liệu, đề nghị liên hệ với Ban bảo đảm chất lượng để rà soát và cập nhật theo thực tiễn. Cán bộ, giảng viên và người lao động được cung cấp file mềm trên mạng nội bộ để chia sẻ thông tin khi cần.*	609	[-0.02844583,-0.008804259,-0.010512652,-0.014533875,-0.03260822,-0.04130312,-0.005516755,0.00240859,-0.011140827,-0.0009357633,0.0034639465,0.017202053,-0.026145492,0.017684156,0.029579017,0.016033452,-0.003663959,0.00229895,-0.012939258,-0.019504363,-0.02293202,0.008145433,0.038301982,0.0048374617,0.027865125,-0.014575666,0.00791611,-0.043896887,0.03026112,0.0018992415,0.0080176685,0.0043365983,0.014255039,-0.030136816,0.009457674,-0.022820434,-0.0066022784,-0.067875,-0.028366268,0.026515463,-0.006905272,-0.022916457,-0.005854949,-0.044344973,0.03329165,-0.007659573,0.003500796,-0.043454606,-0.008315052,-0.011246465,-0.022604132,0.019513017,0.07881011,-0.016529286,-0.009149959,0.02436694,0.00496993,-0.016606374,-0.06893051,0.015168198,-0.019081831,0.0039887624,-0.01300416,-0.044297848,0.0059306924,-0.027792804,0.03542323,0.008305233,0.010733992,-0.032321543,0.031289402,0.012139746,-0.037522566,-0.021539526,-0.069234125,0.033845928,0.010060252,-0.024357578,0.00933072,0.024298897,-0.02124595,0.020355685,0.023540124,-0.0159125,0.0004697352,-0.037729174,0.0021177072,0.052555066,0.04049274,0.010905989,-0.044440456,0.0210954,-0.015488046,-0.025912333,-0.030753924,-0.016126972,-0.026287755,-0.014113389,-0.0026748145,0.01